        dres = nearest_dist(nx, ny)
        dopt = abs(nx - ox) + abs(ny - oy)
        if dres is None:
            score = dopt
        else:
            score = -dres + 0.01 * dopt
        if score > best_score:
            best_score = score
            best_move = (dx, dy)

    return [best_move[0], best_move[1]]

