    grid_w = observation.get("grid_width", 8)
    grid_h = observation.get("grid_height", 8)
    if not resources:
        return [0, 0]

    def dist(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def clamp(v, lo, hi):
        return lo if v < lo else hi if v > hi else v

    moves = [(dx, dy) for dx in (-1, 0, 1) for dy in (-1, 0, 1)]
